import { Injectable, signal } from '@angular/core';

export type ToastKind = 'success' | 'error' | 'info' | 'warning';

export interface Toast {
  id: number;
  kind: ToastKind;
  message: string;
  durationMs: number;
}

@Injectable({ providedIn: 'root' })
export class ToastService {
  readonly toasts = signal<Toast[]>([]);
  private nextId = 1;

  success(message: string, durationMs = 3500) { this.push('success', message, durationMs); }
  error(message: string, durationMs = 6000)   { this.push('error', message, durationMs); }
  info(message: string, durationMs = 3500)    { this.push('info', message, durationMs); }
  warning(message: string, durationMs = 4500) { this.push('warning', message, durationMs); }

  dismiss(id: number) {
    this.toasts.update(arr => arr.filter(t => t.id !== id));
  }

  private push(kind: ToastKind, message: string, durationMs: number) {
    const id = this.nextId++;
    this.toasts.update(arr => [...arr, { id, kind, message, durationMs }]);
    setTimeout(() => this.dismiss(id), durationMs);
  }
}
